DROP TABLE IF EXISTS `Method`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `Method` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '唯一主键',
  `from` tinyint NOT NULL DEFAULT '0' COMMENT '来源：0-接口工具；1-CI/CD；2-流量录制',
  `userId` bigint NOT NULL COMMENT '管理员用户Id',
  `language` varchar(30) DEFAULT NULL COMMENT '所属编程语言，例如 Java, Go, Kotlin 等',
  `group` varchar(45) DEFAULT NULL COMMENT '分组名称',
  `operation` varchar(45) DEFAULT NULL COMMENT '增删改查等操作类别：：INSERT, SELECT, UPDATE, DELETE, LOGIN, REGISTER, GET_VERIFY, EDIT_PASSWORD …',
  `ui` tinyint NOT NULL DEFAULT '0' COMMENT '0-非 UI 方法，1 - UI 方法',
  `static` tinyint NOT NULL DEFAULT '0' COMMENT '是否为 static 方法： 0-false; 1-true',
  `package` varchar(500) DEFAULT NULL COMMENT '包名',
  `class` varchar(50) DEFAULT NULL COMMENT '类名，注意内部类需要写成 外部类名$内部类名，例如 SharedPreferences$Editor',
  `constructor` varchar(50) DEFAULT NULL COMMENT '构造方法名，一般不传，默认为类名；传的话主要是用在单例模式类的 getInstance 等方法',
  `classArgs` text COMMENT '[\n        {   //User user\n            "type": "apijson.demo.server.model.User",\n            "value": {\n                "id": 1,\n                "name": "APIJSON"\n            }\n        },\n        {   //String id，不填 type 的话会根据 value 自动确定\n            "value": "id"\n        }\n]',
  `genericClassArgs` text COMMENT '带泛型的构造方法参数名，例如\n[\n        {   //List<User> list\n            "type": “java.util.List<T>”,\n            "value": [{\n                "id": 1,\n                "name": "APIJSON"\n            }]\n        },\n        {   //String id，不填 type 的话会根据 value 自动确定\n            "value": "id"\n        }\n]',
  `Method` varchar(50) NOT NULL COMMENT '方法名',
  `methodArgs` text COMMENT '参数列表，格式是\n[\n        {   //User user\n            "type": "apijson.demo.server.model.User",\n            "value": {\n                "id": 1,\n                "name": "APIJSON"\n            }\n        },\n        {   //String id，不填 type 的话会根据 value 自动确定\n            "value": "id"\n        }\n]',
  `genericMethodArgs` text COMMENT '带泛型的方法参数名，例如\n[\n        {   //List<User> list\n            "type": “java.util.List<T>”,\n            "value": [{\n                "id": 1,\n                "name": "APIJSON"\n            }]\n        },\n        {   //String id，不填 type 的话会根据 value 自动确定\n            "value": "id"\n        }\n]',
  `exceptions` varchar(500) DEFAULT NULL COMMENT '异常类型列表',
  `genericExceptions` varchar(500) DEFAULT NULL COMMENT '带泛型的异常类型列表',
  `type` varchar(50) DEFAULT NULL COMMENT '返回值类型。TODO RemoteMethod 校验 type 和 back',
  `genericType` varchar(50) DEFAULT NULL COMMENT '带泛型的返回值类型',
  `request` text COMMENT '完整请求',
  `demo` json DEFAULT NULL COMMENT '可用的示例。\nTODO 改成 call，和返回值示例 back 对应。',
  `detail` varchar(1000) NOT NULL COMMENT '详细描述',
  `date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `index_date` (`date`),
  KEY `index_package` (`package`),
  KEY `index_class` (`class`),
  KEY `index_method` (`Method`),
  KEY `index_package_class` (`package`,`class`),
  KEY `index_package_class_method` (`package`,`class`,`Method`)
) ENGINE=InnoDB AUTO_INCREMENT=1703475324632 DEFAULT CHARSET=utf8mb3 COMMENT='要做单元测试的方法(如果用到单元测试，则必须)';
